VALUES
  ('retired-8b44517b-moex-00320', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '在經濟體系中有兩位消費者（A和B），兩種財貨（X和Y）。消費者A的初始稟賦為（X=8,Y=12） 而消費者B的初始稟賦為（X=12,Y=8）。消費者A和B的效用函數皆為U(X,Y)=X２Y２。此市場 均衡的相對價格（P /P ）為何？ X Y', '["1", "2", "3", "4"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00321', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '當火力發電廠燃煤量過大，導致嚴重的空氣污染問題時，政府介入卻無法解決相關的污染問題， 則我們稱此現象為：', '["政府失靈", "價格機能", "市場機能", "政府信用破產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00322', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '假設A國成年人口為46百萬人，勞動參與率為75%，失業率為8%。則A國的就業人口為：', '["2.76百萬人", "31.74百萬人", "34.5百萬人", "42.32百萬人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00323', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '關於梭羅（Solow）之新古典成長理論（neoclassicalgrowththeory）的敘述，下列何者正確？', '["長期經濟成長最重要的內生變數是技術", "存在最適儲蓄率的黃金法則（goldenrule）", "認為人力資本具有外溢效果", "由於富國技術進步較快，故富國和窮國的貧富差距將擴大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00324', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '就純公共財而言，增加一位消費者對此財貨提供造成的邊際成本：', '["等於邊際效益", "小於邊際效益", "等於零", "大於零"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00325', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '根據凱因斯流動性偏好理論（liquiditypreferencetheory），下列敘述何者正確？', '["在其他條件不變下，中央銀行增加貨幣供給，均衡實質利率會下降", "在其他條件不變下，當預期通貨膨脹愈低，則其貨幣持有就越低", "在其他條件不變下，實質所得上升，貨幣供給將會提高", "經濟處於流動性陷阱（liquidity trap）時，其貨幣需求的利率彈性（interest elasticity of money demand）趨近無窮大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00326', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '考慮一個開放總體經濟，假設本國只生產單一商品且本國商品價格固定，民眾對於匯率預期是採 取靜態預期，而資本在國際間完全自由移動，且中央銀行並無實施沖銷干預（sterilized intervention）。根據前述設定，下列敘述何者錯誤？', '["財政政策於固定匯率制度下，對產出最為有效", "固定匯率制度下的財政乘數小於浮動匯率制度下的財政乘數", "資本於國際間自由移動，以致於本國利率釘住國外利率。在固定匯率制度下，寬鬆財政政策並 不影響到利率，從而沒有發生排擠私部門投資", "中央銀行的擴張性貨幣政策，於固定匯率制度之下，將失去貨幣自主性（monetaryautonomy）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00327', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '根據IS-LM與AD-AS模型，當石油開採技術進步時，在其他條件不變下，對非產油國而言，如 果其貨幣需求對所得愈敏感，則其：', '["短期均衡實質GDP與一般物價水準的增幅皆愈大", "短期均衡實質GDP的增幅愈大且一般物價水準的降幅愈小", "短期均衡實質GDP的增幅愈小且一般物價水準的降幅愈大", "短期均衡實質GDP的增幅愈小且一般物價水準的降幅愈小"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00328', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '在梭羅模型（SolowModel），儲蓄率上升造成：', '["長短期勞工平均產出都增加", "長短期勞工平均產出都減少", "長期勞工平均產出增加，短期勞工平均產出減少", "長期勞工平均產出減少，短期勞工平均產出增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00329', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '在封閉體系且考慮政府部門下，假設邊際消費傾向為0.8，邊際稅率為0.25，充分就業產出為5000 萬，而目前經濟體系的均衡產出為4000萬，請問政府定額稅該採何種方式，才會使經濟體系達到 充分就業產出？', '["減稅2000萬", "增稅2000萬", "增稅500萬", "減稅500萬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL)
